#include <stdio.h>
#include <string.h>
int repeatedStringMatch(char * A, char * B) {
    int lenA = strlen(A), lenB = strlen(B);
    int count = (lenB + lenA - 1) / lenA;
    char *str = (char *)malloc((count + 2) * lenA * sizeof(char));
    for (int i = 0; i < count + 2; i++) {
        strcat(str, A);
    }
    if (strstr(str, B)) return count;
    if (strstr(str + lenA, B)) return count + 1;
    free(str);
    return -1;
}

code.C++:
#include <string>
using namespace std;
int repeatedStringMatch(string A, string B) {
    int lenA = A.size(), lenB = B.size();
    int count = (lenB + lenA - 1) / lenA;
    string str;
    for (int i = 0; i < count + 2; i++) {
        str += A;
    }
    if (str.find(B) != string::npos) return count;
    if (str.substr(lenA).find(B) != string::npos) return count + 1;
    return -1;
}

code.Java:
public class Solution {
    public int repeatedStringMatch(String A, String B) {
        int lenA = A.length(), lenB = B.length();
        int count = (lenB + lenA - 1) / lenA;
        StringBuilder str = new StringBuilder();
        for (int i = 0; i < count + 2; i++) {
            str.append(A);
        }
        if (str.indexOf(B) != -1) return count;
        if (str.substring(lenA).indexOf(B) != -1) return count + 1;
        return -1;
    }
}

