var repeatedStringMatch = function(A, B) {
    let lenA = A.length, lenB = B.length;
    let count = Math.ceil(lenB / lenA);
    let str = A.repeat(count + 2);
    if (str.includes(B)) return str.indexOf(B) === str.lastIndexOf(B) ? count : count + 1;
    return -1;
};
